-- ---- Column Comments ----
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CID COMMENT 'Customer ID. The eToro platform''s primary customer identifier (RealCID from Fact_SnapshotCustomer). HASH distribution key. One or two rows per CID per DateID depending on transfer status. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TransferDirection COMMENT 'Regulation/credit-valid transfer indicator. 1 = current regulation row (or no transfer). -1 = previous regulation row. For non-transfer CIDs this is always 1. Critical for correct aggregation: always SUM+GROUP BY CID to avoid double counting. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Regulation COMMENT 'Name of the regulatory entity governing this customer row. Values: FCA, CySEC, ASIC, SIBA, SFSA, FSA, etc. Resolved from Dim_Regulation.Name via Fact_SnapshotCustomer.RegulationID. For transfer CIDs, the -1 row shows the previous regulation. (Tier 1 - Dictionary.Regulation)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN IsCreditReportValidCB COMMENT 'Credit Bureau reporting eligibility flag. 1 = eligible for credit reporting. Inherited from Fact_SnapshotCustomer. Excludes demo non-real accounts, internal labels (26,30), and blocked countries (250). Used by finance for regulatory balance reconciliation. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotCustomer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN DidRegulationTransfer COMMENT '1 if this CID''s RegulationID changed between yesterday and today, 0 otherwise. When 1, the CID has two rows: TransferDirection=1 (new regulation) and TransferDirection=-1 (old regulation). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN DidCBValidTransfer COMMENT '1 if this CID''s IsCreditReportValidCB flag changed between yesterday and today, 0 otherwise. Triggers the same two-row split as DidRegulationTransfer. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN IsEtoroTradingCID COMMENT '1 if CID is one of eToro''s internal trading group accounts (hardcoded list: 2244852, 2283663, 2283668, 5969868, 5969870, 5969875, 5969866). Used to exclude eToro''s own trading activity from client-facing reports. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN eToroTradingGroupUser COMMENT 'UserName from Dim_Customer for eToro trading group accounts; ''NotEtoroGroupAccount'' for all others. Identifies which eToro group user this row belongs to. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN IsGlenEagleAccount COMMENT '1 if CID = 14155290 (the GlenEagle account), 0 otherwise. Hardcoded identifier for a specific institutional account used in reporting exclusions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Region COMMENT 'Geographic region from Dim_Country.Region. Values: German, Eastern Europe, Nordics, Middle East, China, etc. Used for regional balance reporting and DDR segmentation. (Tier 2 - SP_Client_Balance_New, join-enriched from DWH_dbo.Dim_Country)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN FromRegulation COMMENT 'The regulation the CID transferred FROM. For non-transfer CIDs, equals the current Regulation. For transfer CIDs, shows the previous regulation name. Resolved from #VRegTransfers_Max. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ToRegulation COMMENT 'The regulation the CID transferred TO. For non-transfer CIDs, equals the current Regulation. For transfer CIDs, shows the new regulation name. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN AccountType COMMENT 'Account type name from Dim_AccountType. Values: Private, Corporate. (Tier 1 - Dictionary.AccountType)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Label COMMENT 'Customer label from Dim_Label. Used for marketing segmentation and internal user categorization. (Tier 1 - Dictionary.Label)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Country COMMENT 'Country name from Dim_Country. The customer''s registered country. (Tier 1 - Dictionary.Country)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN MifidCategory COMMENT 'MiFID II client categorization from Dim_MifidCategorization. Values: Retail, Professional, Retail Pending, Professional Pending. Determines regulatory protections and reporting requirements. (Tier 1 - Dictionary.MifidCategorization)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Club COMMENT 'eToro Club tier from Dim_PlayerLevel. Values: Bronze, Silver, Gold, Platinum, Platinum Plus, Diamond. Determines benefits such as interest on balance eligibility. (Tier 1 - Dictionary.PlayerLevel)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PlayerStatus COMMENT 'Customer account status from Dim_PlayerStatus. Values: Active, Blocked, Active - Cannot Login, Blocked Upon Request, etc. Filter: PlayerStatusID NOT IN (1,3,5,7) = blocked. (Tier 1 - Dictionary.PlayerStatus)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN DateID COMMENT 'Date identifier in YYYYMMDD integer format. Clustered index column. The date this balance snapshot represents. Filter on this column for efficient date-range queries. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN OpeningBalance COMMENT 'Customer''s balance at the start of the business day (in USD). Equals the previous day''s ClosingBalance for this CID. Source: V_Liabilities (previous day). For the first row per CID, this is the initial deposit amount. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Deposits COMMENT 'Total deposits. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID IN (7,44). Includes both external deposits (7) and internal transfers (44). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CompensationDeposit COMMENT 'Deposit-type compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID = 7. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Bonus COMMENT 'Bonus credits. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=9. Credit bonus amounts applied to account. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Compensation COMMENT 'General compensation. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=36 AND CompensationReasonID NOT IN (7,8,11,18,19,22,30,31,32,33,34,36,37,38,40,41,50,51,52). Excluded IDs are captured in dedicated columns (7=CompDeposit, 8/51/52=Affiliate, 11=NegRefill, 19=NWAAdj, 22=PnLAdj, 30=DormantFee, 31=LostDebt, 32=Foreclosure, 33=CompCashout, 41/50=PI). Reason 17 re-included per SR-280376 (Nov 2024). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CompensationPI COMMENT 'PI compensation. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=36 AND CompensationReasonID IN (41,50). Performance Incentive payouts to popular investors. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CompensationToAffiliate COMMENT 'Affiliate compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (8,51,52). Payouts to affiliate/partner accounts. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NWAAdjustment COMMENT 'NWA adjustment compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (19). Adjustments to Net Withdrawable Amount. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NegativeRefill COMMENT 'Negative balance protection refill. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (11). Platform refills retail client balance to zero after CFD/futures losses exceed available funds. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Cashouts COMMENT 'Cashout withdrawals. SUM(Amount) from Fact_CustomerAction WHERE (ActionTypeID=8 AND IsRedeem!=1) OR ActionTypeID=45. Excludes crypto redemptions (IsRedeem=1). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CashoutsIncludingRedeem COMMENT 'Total cashouts including redeems. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID IN (8,45). Broader than Cashouts - includes crypto redemptions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CompensationCashouts COMMENT 'Cashout-type compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (33). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CashoutFee COMMENT 'Cashout fee. -SUM(Commission) + SUM(CASE WHEN IsRedeem=1 THEN Commission END) from Fact_CustomerAction WHERE ActionTypeID=30. Excludes crypto redemption commissions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Chargeback COMMENT 'Chargeback amounts. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID IN (11,13). Disputed deposit reversals. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Refund COMMENT 'Refund amounts. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=12. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN OvernightFee COMMENT 'Overnight/rollover fees. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35. CFD swap fees charged for holding positions overnight/weekend. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN LostDebt COMMENT 'Lost debt write-off. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (31). Uncollectable amounts written off. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ChargebackLoss COMMENT 'Loss from chargebacks that could not be recovered. Split by TransferDirection for regulation transfer CIDs. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN OtherNegatives COMMENT 'Other negative balance adjustments not captured in specific columns. Split by TransferDirection for regulation transfer CIDs. Catch-all for miscellaneous balance reductions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Foreclosure COMMENT 'Foreclosure amounts. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (32). Forced position closures due to margin calls or regulatory requirements. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CompensationPnLAdjustments COMMENT 'PnL adjustment compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (22). Corrections to realized PnL via compensation mechanism. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CompensationDormantFee COMMENT 'Dormant fee compensation. SUM(Amount) from Fact_CustomerAction WHERE CompensationReasonID IN (30). Refunds of inactivity fees charged to dormant accounts. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceRealizedPnL COMMENT 'Total realized PnL. SUM(NetProfit) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40). All closed positions across all asset classes. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceRealizedPnLCFD COMMENT 'CFD realized PnL. SUM(NetProfit) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,30) AND IsSettled=0. CFD (non-settled) position closes only. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceRealizedPnLRealStocks COMMENT 'Realized PnL from real (settled) stock position closes. IsSettled=1 AND InstrumentTypeID IN (5,6). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceRealizedPnLRealCrypto COMMENT 'Realized PnL from real (settled) crypto position closes. IsSettled=1 AND InstrumentTypeID=10. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TransferCoins COMMENT 'Crypto coin transfers. -SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=8 AND IsRedeem=1. Blockchain wallet-to-wallet movements (sign-inverted). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TransferCoinFees COMMENT 'Crypto transfer fees. -SUM(Commission) from Fact_CustomerAction WHERE ActionTypeID=30 AND IsRedeem=1. Blockchain network + eToro transfer fees. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClosingBalance COMMENT 'Customer''s balance at end of business day (USD). From V_Liabilities. Tomorrow''s OpeningBalance = today''s ClosingBalance. The cycle equation must hold: OpeningBalance + all flows = ClosingBalance. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN realizedEquity COMMENT 'Total account value including unrealized PnL on open positions. From Fact_SnapshotEquity.RealizedEquity. Confluence: "the total funds in the account, including profit/loss from open positions." (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN RealCryptoOpenBalance COMMENT 'Previous day''s total real crypto position value. From Fact_SnapshotEquity.TotalRealCrypto (yesterday). Used to calculate day-over-day crypto balance change. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN RealCryptoClosingBalance COMMENT 'Today''s total real crypto position value. From Fact_SnapshotEquity.TotalRealCrypto. IsSettled=1 AND InstrumentTypeID=10. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientMoneyOpenBalance COMMENT 'Previous day''s client money (NWA). From V_Liabilities.ActualNWA (yesterday). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientMoneyClosingBalance COMMENT 'Today''s client money (NWA). From V_Liabilities.ActualNWA. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN RealStocksOpeningBalance COMMENT 'Previous day''s total real stock position value. From Fact_SnapshotEquity.TotalRealStocks (yesterday). (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN RealStocksClosingBalance COMMENT 'Today''s total real stock position value. From Fact_SnapshotEquity.TotalRealStocks. IsSettled=1 AND InstrumentTypeID IN (5,6). (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceFullCommission COMMENT 'Total full commission. -SUM(FullCommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40). All asset classes combined. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceCommission COMMENT 'Total net commission. -SUM(CommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40). Client''s portion across all asset classes. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceFullCommissionCFD COMMENT 'CFD full commission. -SUM(FullCommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=0. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceCommissionCFD COMMENT 'CFD net commission. -SUM(CommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=0. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceFullCommissionRealCrypto COMMENT 'Real crypto full commission. -SUM(FullCommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=1 AND InstrumentTypeID=10. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceCommissionRealCrypto COMMENT 'Real crypto net commission. -SUM(CommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=1 AND InstrumentTypeID=10. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceFullCommissionRealStocks COMMENT 'Real stocks full commission. -SUM(FullCommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=1 AND InstrumentTypeID IN (5,6). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceCommissionRealStocks COMMENT 'Real stocks net commission. -SUM(CommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=1 AND InstrumentTypeID IN (5,6). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN DividendsPaid COMMENT 'Dividend payments. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35 AND IsFeeDividend=1. Real stock and ETF holders receive dividends. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalLiability COMMENT 'Total liability from open positions. From V_Liabilities.Liabilities. Represents the unrealized obligation (positive = amount owed to customer; negative = customer owes). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalNegativeLiability COMMENT 'Negative portion of total liability. Used in regulatory reporting to isolate client obligations. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN WithdrawableLiability COMMENT 'Liability component that is available for withdrawal. From V_Liabilities.WithdrawableLiability. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NegativeWithdrawableLiability COMMENT 'Negative portion of withdrawable liability. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN LiabilityInUsedMargin COMMENT 'Liability locked in used margin for leveraged positions. Not available for withdrawal. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NegativeLiabilityInUsedMargin COMMENT 'Negative portion of liability in used margin. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN InProcessCashout COMMENT 'Pending cashout amount not yet finalized. From Fact_SnapshotEquity.InProcessCashouts. Excludes statuses 3=Processed, 4=Cancelled, 5, 6. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NegativeInProcessCashout COMMENT 'Negative portion of in-process cashouts. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NOPCrypto COMMENT 'Net Open Position for crypto instruments. From V_Liabilities. Represents the net market exposure in crypto. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NOPCryptoCFD COMMENT 'NOP for crypto CFDs specifically (not settled/real crypto). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NOPStocks COMMENT 'Net Open Position for stock instruments. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NOPStocksCFD COMMENT 'NOP for stock CFDs specifically. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalRealCryptoLoan COMMENT 'Total leveraged real crypto loan amount. InitialAmount where IsSettled=1 AND InstrumentTypeID=10 AND Leverage=2. Represents the initial investment in 2x leveraged crypto. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalRealCrypto COMMENT 'Total real crypto position value. Sum of position amounts where IsSettled=1 AND InstrumentTypeID=10. Customer owns the underlying crypto asset. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalRealStocks COMMENT 'Total real stock position value. Sum of position amounts where IsSettled=1 AND InstrumentTypeID IN (5,6) AND NOT futures. Customer owns the underlying shares. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionPNLCryptoReal COMMENT 'Position PnL for real (settled) crypto positions. Unrealized profit/loss on owned crypto. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionPNLStocksReal COMMENT 'Position PnL for real (settled) stock positions. Unrealized profit/loss on owned shares. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionPNL COMMENT 'Total position PnL across all asset classes. From V_Liabilities.PositionPnL. Unrealized profit/loss on all open positions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN AvailableCash COMMENT 'Cash available for trading. From V_Liabilities.AvailableCash. Free cash not locked in positions or pending cashouts. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CashInCopy COMMENT 'Cash allocated to copy-trading relationships. From V_Liabilities.CashInCopy. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NOP COMMENT 'Total Net Open Position across all asset classes. From V_Liabilities.NOP. Net market exposure. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionAmount COMMENT 'Total position amount (sum of all open position values). From Fact_SnapshotEquity.TotalPositionsAmount. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN StockOrders COMMENT 'Stock order amount. Legacy column - hardcoded to 0 in Fact_SnapshotEquity since 2019-03-03. Kept for schema compatibility. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN actualNWA COMMENT 'Actual Net Withdrawable Amount. From V_Liabilities.ActualNWA. The amount the customer could withdraw right now. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UsedBonus COMMENT 'Bonus credit amount currently used in open positions. Change metric (day-over-day). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedCommissionChange COMMENT 'Day-over-day change in total unrealized commission. Commission accrued but not yet realized (positions still open). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedFullCommissionChange COMMENT 'Day-over-day change in full unrealized commission (including eToro''s spread). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedPnLChange COMMENT 'Day-over-day change in total unrealized PnL across all asset classes. Key metric for equity volatility tracking. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedPnLChangeCFD COMMENT 'Day-over-day change in unrealized PnL for CFD positions only. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedPnLChangeCryptoReal COMMENT 'Day-over-day change in unrealized PnL for real crypto positions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedPnLChangeStocksReal COMMENT 'Day-over-day change in unrealized PnL for real stock positions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedFullCommissionChangeRealStocks COMMENT 'Day-over-day change in full unrealized commission for real stocks. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalNetTransfers COMMENT 'Net financial impact of regulation transfers. Sum of all balance components transferred when a CID moves between regulations. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalTransfersInvestedRealStocks COMMENT 'Real stock position value component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalTransfersInvestedRealCrypto COMMENT 'Real crypto position value component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetTransfersNWA COMMENT 'NWA (Net Withdrawable Amount) component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetTransfersUnrealizedPnL COMMENT 'Unrealized PnL component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetTransfersLiability COMMENT 'Liability component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetLiabilityTransferStocks COMMENT 'Stock-specific liability in regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetUnrealizedPnLTransferStocks COMMENT 'Stock-specific unrealized PnL in regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UpdateDate COMMENT 'ETL metadata: timestamp when this row was last updated by the ETL pipeline. Set to GETDATE() during SP_Client_Balance_New execution. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionPnLCrypto COMMENT 'PnL for all crypto positions (CFD + real). From V_Liabilities.PositionPnLCrypto. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionPnLStocks COMMENT 'PnL for all stock positions (CFD + real). From V_Liabilities.PositionPnLStocks. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalCryptoPositionAmount COMMENT 'Total crypto position value (CFD + real). From Fact_SnapshotEquity.TotalCryptoPositionAmount. InstrumentTypeID=10. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalStocksPositionAmount COMMENT 'Total stock position value (CFD + real). From Fact_SnapshotEquity.TotalStockPositionAmount. InstrumentTypeID IN (5,6). (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN IsGermanBaFin COMMENT '1 if the customer is under German BaFin regulatory supervision (present in V_GermanBaFin for this date), 0 otherwise. Used for BaFin-specific reporting. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN IsValidCustomer COMMENT 'Segment flag from Fact_SnapshotCustomer. 1 = valid retail customer (not demo, not internal label, not blocked country). Use `WHERE IsValidCustomer = 1` for most analytics. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotCustomer)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Date COMMENT 'The business date as a DATE type. Equivalent to DateID but in date format. Computed from @date SP parameter. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN YearMonth COMMENT 'Year-month in YYYYMM format (e.g., 202603). Computed as CONVERT(VARCHAR(6), @date, 112). Used for monthly aggregation. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN YearQuarter COMMENT 'Year-quarter in YYYYQQ format (e.g., 202601). Computed as YEAR(@date) * 100 + DATEPART(qq, @date). Used for quarterly reporting. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN Year COMMENT 'Calendar year (e.g., 2026). Computed from @date parameter. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedCommissionChangeRealStocks COMMENT 'Day-over-day change in unrealized commission for real (settled) stock positions. Added for FINRA data requirements (Aug 2021). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalRealStocksEquityChange COMMENT 'Day-over-day change in total real stocks equity (position value + PnL). Added for FINRA adjustments (Sep 2021). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CompensationsApexUSStocks COMMENT 'Apex US stocks compensation. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=36 AND CompensationReasonID IN (45,60,62,63,64,65,66,67,68,69,70,71,72,75,76,78,79,81,82,83,84,85,86,87,88,89,92,17,18,73,74,77,104,114,120) AND Regulation=''FinCEN+FINRA''. Per SR-283800. Excludes reason 91 (crypto staking overlap). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedFullCommissionChangeCFDStocks COMMENT 'Day-over-day change in full unrealized commission for CFD stock positions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedFullCommissionChangeRealCrypto COMMENT 'Day-over-day change in full unrealized commission for real crypto positions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedFullCommissionChangeCFDCrypto COMMENT 'Day-over-day change in full unrealized commission for CFD crypto positions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TRSCryptoOpeningBalance COMMENT 'Previous day''s TRS (Total Return Swap) crypto position value. From Fact_SnapshotEquity.Total_TRSCrypto (yesterday). Added Jan 2022. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TRSCryptoClosingBalance COMMENT 'Today''s TRS crypto position value. From Fact_SnapshotEquity.Total_TRSCrypto. TRS has different regulatory treatment than settled positions. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedPnLChangeCryptoTRS COMMENT 'Day-over-day change in unrealized PnL for TRS crypto positions. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalCryptoPositionAmountTRS COMMENT 'TRS crypto position amount. From Fact_SnapshotEquity.TotalCryptoPositionAmount_TRS. SettlementTypeID=2 positions. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceRealizedPnLRealCryptoTRS COMMENT 'TRS crypto realized PnL. SUM(NetProfit) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,30) AND IsSettled=1 AND InstrumentTypeID=10 AND SettlementTypeID=3. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceFullCommissionTRSCrypto COMMENT 'TRS crypto full commission. -SUM(FullCommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=1 AND InstrumentTypeID=10 AND SettlementTypeID=3. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceCommissionTRSCrypto COMMENT 'TRS crypto net commission. -SUM(CommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=1 AND InstrumentTypeID=10 AND SettlementTypeID=3. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedFullCommissionChangeTRSCrypto COMMENT 'Day-over-day change in full unrealized commission for TRS crypto. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NOPCryptoTRS COMMENT 'Net Open Position for TRS crypto. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionPNLCryptoTRS COMMENT 'Position PnL for TRS crypto. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalTRSCrypto COMMENT 'Total TRS crypto position value. From Fact_SnapshotEquity.Total_TRSCrypto. IsSettled=0 AND InstrumentTypeID=10 AND SettlementTypeID=2. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CashoutRollback COMMENT 'Cashout rollback. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=42. Reversed/cancelled cashout amounts. Added Feb 2023. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ReverseDeposit COMMENT 'Reverse deposit. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=43. Failed/reversed deposit amounts. Added Feb 2023. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN DepositConversionFee COMMENT 'Deposit currency conversion fee. Always NULL - placeholder column not yet implemented in the SP. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN WithdrawConversionFee COMMENT 'Withdrawal currency conversion fee. Always NULL - placeholder column not yet implemented in the SP. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN SDRT COMMENT 'Stamp Duty Reserve Tax (UK). SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=35 AND IsFeeDividend=3. Tax on UK stock purchases. Added Oct 2023. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TanganyStatus COMMENT 'Tangany crypto wallet status. Human-readable name from External_UserApiDB_Dictionary_TanganyStatus. Values reflect the customer''s DLT/Tangany wallet lifecycle stage. Added Nov 2023. (Tier 2 - SP_Client_Balance_New, join-enriched from BI_DB_dbo.External_UserApiDB_Dictionary_TanganyStatus)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TradingFees COMMENT 'Trading fees. SUM(Amount) from Fact_CustomerAction WHERE (ActionTypeID=35 AND IsFeeDividend=4) OR (ActionTypeID=36 AND CompensationReasonID IN (117,118)). Separated from OvernightFee for clearer revenue attribution. Added Mar 2024. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN InternalTransferDeposits COMMENT 'Internal transfer deposits. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=44. Inter-entity transfers (regulation migration). Added Mar 2024. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN InternalTransferWithdraws COMMENT 'Internal transfer withdrawals. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=45. Inter-entity transfers (regulation migration). Added Mar 2024. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedCommissionChangeRealCrypto COMMENT 'Day-over-day change in unrealized commission for real crypto positions. Added Apr 2024 for DLT-adjusted client balance. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TicketFee COMMENT 'Fixed ticket fee. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=1000 (synthetic type for fixed-amount ticket fees). Separated from TradingFees per SR-262975 (Jul 2024). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalRealCryptoEquityChange COMMENT 'Day-over-day change in total real crypto equity (position value + PnL). Mirrors TotalRealStocksEquityChange for crypto. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetTransfersUnrealizedPnLCryptoReal COMMENT 'Real crypto unrealized PnL component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetTransfersLiabilityCryptoReal COMMENT 'Real crypto liability component of regulation transfers. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN DidDLTTransfer COMMENT '1 if the customer''s DLT/Tangany status changed between yesterday and today, 0 otherwise. Added Jul 2024. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN IsDLTUser COMMENT '1 if the customer has an active DLT/Tangany wallet (DltStatusID=4 in Fact_SnapshotCustomer), 0 otherwise. Added Jul 2024. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN CompensationCryptoTransferOut COMMENT 'Crypto transfer-out compensation. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=36 AND CompensationReasonID IN (113). DLT/Tangany outbound transfer compensation. Added Oct 2024. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceRealizedPnLRealFutures COMMENT 'Real futures realized PnL. SUM(NetProfit) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,30) AND IsSettled=1 AND InstrumentTypeID IN (1,2,4). Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN RealFuturesOpenBalance COMMENT 'Previous day''s total real futures position value. From Fact_SnapshotEquity.TotalRealFutures (yesterday). Added Jan 2025. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN RealFuturesClosingBalance COMMENT 'Today''s total real futures position value. From Fact_SnapshotEquity.TotalRealFutures. Added Jan 2025. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceFullCommissionRealFutures COMMENT 'Real futures full commission. -SUM(FullCommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=1 AND InstrumentTypeID IN (1,2,4). Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN ClientBalanceCommissionRealFutures COMMENT 'Real futures net commission. -SUM(CommissionOnClose) from Fact_CustomerAction WHERE ActionTypeID IN (4,5,6,28,40) AND IsSettled=1 AND InstrumentTypeID IN (1,2,4). Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NOP_FuturesReal COMMENT 'Net Open Position for real futures. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalRealFutures COMMENT 'Total real futures position value. From Fact_SnapshotEquity.TotalRealFutures. IsFuture=1 from Dim_Instrument_Snapshot. Added Jan 2025. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionPNLFuturesReal COMMENT 'Position PnL for real futures. Unrealized profit/loss on futures. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedPnLChangeFuturesReal COMMENT 'Day-over-day change in unrealized PnL for real futures. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalTransfersInvestedRealFutures COMMENT 'Real futures position value component of regulation transfers. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedFullCommissionChangeRealFutures COMMENT 'Day-over-day change in full unrealized commission for real futures. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN UnrealizedCommissionChangeRealFutures COMMENT 'Day-over-day change in unrealized commission for real futures. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalRealFuturesEquityChange COMMENT 'Day-over-day change in total real futures equity. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetTransfersUnrealizedPnLFuturesReal COMMENT 'Real futures unrealized PnL component of regulation transfers. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetTransfersLiabilityFuturesReal COMMENT 'Real futures liability component of regulation transfers. Added Jan 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalFuturesProviderMargin COMMENT 'Provider margin for futures positions: LotCountDecimal × ProviderMarginPerLot. From Fact_SnapshotEquity.TotalFuturesProviderMargin. Margin required by the futures provider. Added Jan 2025. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalFuturesLockedCash COMMENT 'Cash locked as additional futures margin beyond provider margin: NewAmount - (LotCountDecimal × ProviderMarginPerLot). From Fact_SnapshotEquity.TotalFuturesLockedCash. Added Jan 2025. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TicketFeeByPercent COMMENT 'Percentage-based ticket fee. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=1001 (synthetic type for percent-based ticket fees). Temporarily separated from TicketFee per SR-318329 (Jun 2025). (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN US_State COMMENT 'US state 2-letter abbreviation. From Dim_State_and_Province.ShortName via FSC.RegionID, only populated for US customers (CountryID=219). Added Oct 2025. (Tier 2 - SP_Client_Balance_New, join-enriched from DWH_dbo.Dim_State_and_Province)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NOP_StocksMargin COMMENT 'Net Open Position for margin-traded stocks. SettlementTypeID=5. Added Oct 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN PositionPnLStocksMargin COMMENT 'Position PnL for margin-traded stocks. Added Oct 2025. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalStocksMargin COMMENT 'Total margin stock position value. From Fact_SnapshotEquity.TotalStocksMargin. SettlementTypeID=5. Added Oct 2025. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN TotalStockMarginLoanValue COMMENT 'Loan value for leveraged margin stock positions: InitForexRate × AmountInUnitsDecimal × InitConversionRate - NewAmount. From Fact_SnapshotEquity.TotalStockMarginLoanValue. Added Oct 2025. (Tier 2 - SP_Client_Balance_New, from DWH_dbo.Fact_SnapshotEquity)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN NetTransferCommission COMMENT 'Commission component transferred during regulation changes. Added Oct 2025 alongside unrealized commission transfer. (Tier 2 - SP_Client_Balance_New)';
ALTER TABLE main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_client_balance_cid_level_new ALTER COLUMN C2P COMMENT 'Cash-to-Portfolio. SUM(Amount) from Fact_CustomerAction WHERE ActionTypeID=36 AND CompensationReasonID IN (134). Crypto positions opened from IBAN (eMoney). Added Nov 2025 (SR-344304). (Tier 2 - SP_Client_Balance_New)';

